mapper.select:
SELECT service_id, service_type_id, service_name, description, price, estimated_duration,
       available_status, create_time, update_time
FROM service

    AND service_type_id = #{serviceTypeId}
    AND available_status = #{availableStatus}

ORDER BY service_id

